"""
Shared infrastructure for Spyre KTIR tests.

pytest loads this file automatically before any test module, so the sys.path
setup here runs first — test files need no path boilerplate of their own.

Quick-reference
---------------
- :data:`EXAMPLES`              — registry of example kernels discovered
                                  from ``test/fixtures/*/meta.py``
- :class:`KTIRStructuralTester` — EXAMPLE-based setup + structural assertions
- :class:`KTIRCpuTester`        — extends with numerical CPU execution
- :class:`SinglePassTester`     — run one pass on inline MLIR text

Most shared machinery (``OpInfo``, ``walk_module``, ``make_ktir_mod``,
``StructuralAssertions``, ``compile_to_ttir``) lives in :mod:`utils` — this
file re-exports the names so existing test modules can keep importing them
from ``conftest``.

Troubleshooting
---------------
If you see ``ImportError: cannot import name 'amd' from
'triton._C.libtriton'`` at collection time, something has put Triton's
source ``python/`` on ``sys.path`` **before** the editable-install finder
ran. That exposes the stale ``python/triton.egg-info/entry_points.txt``
(which advertises amd/nvidia/spyre because it was generated by a full-tree
build), overriding the installed ``triton-*.dist-info`` that only lists
``spyre``. The result is that ``_discover_backends`` tries to import
``triton.backends.amd.compiler``, which needs C++ symbols that Spyre-only
builds don't compile.

Fixes, in order of preference:

1. Make sure nothing in your shell or test runner sets
   ``PYTHONPATH=.../python`` — the editable install in ``.venv`` already
   resolves ``import triton`` correctly.
2. Delete the stale ``python/triton.egg-info/`` directory
   (``rm -rf python/triton.egg-info``). It gets regenerated on next build
   from the current ``TRITON_BACKENDS`` set.
3. Rebuild the venv from scratch per ``CLAUDE.md``.
"""

import importlib.util
import re
import sys
import tempfile
from pathlib import Path

# ---------------------------------------------------------------------------
# sys.path setup — must happen before any triton / backend imports
#
# We add only ``third_party/spyre/`` to sys.path so ``SpyreBackend`` can
# locate its ``backend.compiler`` module. The Triton package itself is
# loaded via the editable install in the venv (see
# ``.venv/.../__editable___triton_*.pth``), which maps ``triton`` to
# ``python/triton`` with the correct dist-info.
#
# We intentionally do **not** insert ``python/`` onto sys.path here.
# Doing so surfaces the stale ``python/triton.egg-info/entry_points.txt``
# metadata generated by full-tree builds (listing amd+nvidia+spyre), which
# shadows the installed ``triton-*.dist-info`` and causes
# ``importlib.metadata.entry_points`` to discover ``triton.backends.amd``
# and fail with ``ImportError: cannot import name 'amd'`` for Spyre-only
# builds where the ``amd`` C++ symbols aren't compiled in.
# ---------------------------------------------------------------------------

_triton_root = Path(__file__).resolve().parents[3]
sys.path.insert(0, str(_triton_root / "third_party" / "spyre"))

_TEST_DIR = Path(__file__).parent
_FIXTURES_DIR = _TEST_DIR / "fixtures"


# Re-export helpers from utils so tests can still import them from conftest.
from utils import (  # noqa: E402
    OpInfo,
    StructuralAssertions,
    compile_to_ttir,
    make_ktir_mod,
    walk_module,
)


# ---------------------------------------------------------------------------
# EXAMPLES — registry of example kernels used by tests
#
# Populated by discovery over test/fixtures/*/meta.py: each meta.py exports
# a ``VARIANTS`` dict that gets expanded into one entry per variant, plus
# any reference/oracle helpers used by those variants.
#
# Per-variant entry shape (whichever fields the variant supplies):
#   kernel_fn     : @triton.jit function compiled on demand
#   signature     : dict[str, str] — runtime ABI types
#   constexprs    : dict[str, scalar] — compile-time constants
#   grid          : list[int] — per-axis hardware partition; one entry
#                   per tl.program_id axis read by the kernel. Passed
#                   to DistributeWork via SpyreOptions. Defaults to the
#                   backend's (32,) when omitted.
#   reference     : (inputs) -> np.ndarray — NumPy oracle
#   inputs        : lambda c: {"argN": np.array, ...}
#   output_key    : which inputs key holds the output buffer
#   func_name     : KTIR function name (defaults to kernel_fn.__name__)
#   extra_checks  : optional (tester) -> None for variant-specific asserts
#   xfail_numerical : optional str | dict for the numerical-test xfail mark
#
# Deferred (DISCUSSION_kernel_examples.md): the ``constexprs`` grammar
# currently supports only ``dict[str, scalar]``. List-valued keys for
# Cartesian sweeps and list[dict] for heterogeneous concat will land when
# rms_norm or matmul need parameter sweeps.
# ---------------------------------------------------------------------------


def _import_meta(meta_path: Path):
    """Import ``test/fixtures/<name>/meta.py`` as a package-qualified module.

    The meta.py uses ``from . import kernel``, so we must import it as a
    member of the ``fixtures.<name>`` package — bootstrap the parent
    package first.
    """
    # Pre-register parents so relative imports in meta.py resolve.
    for parent_dir, pkg_name in [
        (_FIXTURES_DIR, "fixtures"),
        (meta_path.parent, f"fixtures.{meta_path.parent.name}"),
    ]:
        if pkg_name in sys.modules:
            continue
        spec = importlib.util.spec_from_file_location(
            pkg_name, parent_dir / "__init__.py",
            submodule_search_locations=[str(parent_dir)],
        )
        mod = importlib.util.module_from_spec(spec)
        sys.modules[pkg_name] = mod
        if spec.loader is not None:
            spec.loader.exec_module(mod)

    name = meta_path.parent.name
    mod_name = f"fixtures.{name}.meta"
    spec = importlib.util.spec_from_file_location(mod_name, meta_path)
    mod = importlib.util.module_from_spec(spec)
    sys.modules[mod_name] = mod
    spec.loader.exec_module(mod)
    return mod


def _resolve_variant(
    module_sig: dict, entry: dict, *, kernel_name: str,
) -> tuple[dict, dict, dict]:
    """Resolve a variant's ``(runtime_signature, constexprs, param_values)``.

    Inputs:
      - ``module_sig`` — module-level ``SIGNATURE`` dict (maps arg name
        to dtype string). Used only if the variant doesn't declare its
        own ``SIGNATURE``.
      - ``entry`` — the fully-merged variant dict. Must declare
        ``constexpr`` (list[str]) and ``params`` (dict[str, list[Any]]).
        May declare ``SIGNATURE`` to override the module-level default
        wholesale (use when the variant's kernel has a different arg
        list, e.g. softmax_multi_tile has BLOCK_N where
        softmax_single_tile has BLOCK_SIZE).

    Outputs:
      - ``runtime_signature`` — ``{name: dtype}`` subset of the effective
        ``SIGNATURE`` for arg names not in the variant's ``constexpr``.
      - ``constexprs`` — ``{name: value}`` for arg names in ``constexpr``.
        The value is ``params[name][0]`` (Cartesian expansion is deferred;
        see ``fixtures/README.md``).
      - ``param_values`` — ``{name: value}`` flattened from ``params``
        using ``[0]``. Used by the numerical test to build runtime kwargs.
    """
    if "params" not in entry:
        raise ValueError(f"{kernel_name}: variant missing 'params'")
    if "constexpr" not in entry:
        raise ValueError(f"{kernel_name}: variant missing 'constexpr'")

    # Flatten single-element lists. (Deferred: Cartesian product when
    # any list has more than one element — rewire discovery to emit
    # one registry entry per product.)
    param_values: dict = {}
    for pname, values in entry["params"].items():
        if not isinstance(values, list) or len(values) != 1:
            raise ValueError(
                f"{kernel_name}: params[{pname!r}] must be a 1-element list "
                f"(Cartesian expansion deferred); got {values!r}"
            )
        param_values[pname] = values[0]

    effective_sig = entry.get("SIGNATURE", module_sig)
    constexpr_names = set(entry["constexpr"])
    runtime_signature = {
        name: dtype for name, dtype in effective_sig.items()
        if name not in constexpr_names
    }
    constexprs = {name: param_values[name] for name in constexpr_names}
    return runtime_signature, constexprs, param_values


def _load_examples():
    registry: dict = {}
    if not _FIXTURES_DIR.exists():
        return registry
    # Only folders with a meta.py qualify as kernel examples.
    for meta_path in sorted(_FIXTURES_DIR.glob("*/meta.py")):
        name = meta_path.parent.name
        mod = _import_meta(meta_path)
        module_sig = getattr(mod, "SIGNATURE", {})
        variants = mod.VARIANTS
        default = variants["default"]
        for vname, delta in variants.items():
            # Shallow merge: variant dict overrides default wholesale per key.
            # Any key the variant omits (constexpr, params, etc.)
            # inherits from default as-is.
            merged = {**default, **delta}
            if module_sig:
                runtime, constexprs, param_values = _resolve_variant(
                    module_sig, merged, kernel_name=f"{name}::{vname}"
                )
                merged["signature"] = runtime
                merged["constexprs"] = constexprs
                merged["param_values"] = param_values
            key = name if vname == "default" else f"{name}__{vname}"
            registry[key] = merged
    return registry


EXAMPLES = _load_examples()


# ---------------------------------------------------------------------------
# KTIRStructuralTester — EXAMPLE-based setup + structural assertions
# ---------------------------------------------------------------------------

class KTIRStructuralTester(StructuralAssertions):
    """Pytest base class for KTIR structural checks on example kernels.

    Subclass, set ``EXAMPLE`` to a key in :data:`EXAMPLES`, and write test
    methods using the assertion helpers inherited from
    :class:`StructuralAssertions`. ``setup_method`` builds ``self.ops``
    automatically.

    The class-level ``EXAMPLE`` is the default; parametrized tests can
    overwrite ``self.EXAMPLE`` before calling ``self.setup_method()``
    manually to target a specific variant.

    Example::

        class TestVectorAdd(KTIRStructuralTester):
            EXAMPLE = "vector_add"

            def test_ktdp_ops(self):
                self.assert_present("ktdp.load", "ktdp.store")
    """

    EXAMPLE: str = None

    def setup_method(self):
        if self.EXAMPLE is None:
            # Parametrized tests set self.EXAMPLE first, then call
            # setup_method() explicitly. The implicit pytest-invoked
            # setup_method runs before parametrize populates it, so
            # skip until the test body re-calls us.
            self._def_map = None
            return
        entry = EXAMPLES[self.EXAMPLE]
        grid = entry.get("grid")  # None → backend default

        if "kernel_fn" in entry:
            ttir_text = compile_to_ttir(
                entry["kernel_fn"],
                entry["signature"],
                entry.get("constexprs", {}),
            )
            with tempfile.NamedTemporaryFile(
                    mode="w", suffix=".mlir", delete_on_close=False) as f:
                f.write(ttir_text)
                f.flush()
                self.mod = make_ktir_mod(f.name, grid=grid)
        else:
            self.mod = make_ktir_mod(entry["path"], grid=grid)

        self.ops = walk_module(self.mod)
        self._def_map = None


# ---------------------------------------------------------------------------
# KTIRCpuTester — adds numerical CPU execution on top of structural checks
# ---------------------------------------------------------------------------

# --- START --- added for spyre: two interchangeable KTIR parsers.
# Both take MLIR text and return a ktir_cpu ``IRModule``. See each helper.

def _parse_mlir_frontend(mlir_text: str):
    """Parse via MLIRFrontendParser in a subprocess; return an IRModule.

    Why a subprocess (TEMPORARY WORKAROUND): ``libtriton.so`` and ``mlir_ktdp``
    each *statically embed their own copy* of MLIR (same LLVM, but two runtimes
    in one process — matching ``llvm-hash-spyre.txt`` makes them source-
    compatible, not shared). Co-loading both and parsing a non-trivial module
    segfaults from duplicate MLIR global state. So we parse in a short-lived
    worker that imports only ``mlir_ktdp`` (never ``triton``) and ship the
    ``IRModule`` back over a pipe as a pickle; the two MLIR copies never
    coexist. Execution stays in-process (pure Python + numpy).

    TODO: drop the subprocess once a single shared MLIR is used by both — e.g.
    a shared ``libMLIR.dylib`` (artifact built with ``MLIR_BUILD_MLIR_DYLIB``)
    that both ``libtriton`` and ``mlir_ktdp`` link, instead of each
    static-embedding its own.

    Raises RuntimeError with the worker's stderr if parsing fails (e.g.
    mlir_ktdp not installed).
    """
    import pickle
    import subprocess
    import sys
    # Worker source: reads MLIR text on stdin, writes a pickled IRModule on
    # stdout. Kept here because it only runs in this fresh, triton-free process.
    worker = (
        "import sys, pickle\n"
        "from ktir_cpu.mlir_frontend.parser import MLIRFrontendParser\n"
        "text = sys.stdin.buffer.read().decode()\n"
        "module = MLIRFrontendParser().parse_module(text)\n"
        "sys.stdout.buffer.write(pickle.dumps(module))\n"
    )
    proc = subprocess.run(
        [sys.executable, "-c", worker],
        input=mlir_text.encode(),
        capture_output=True,
    )
    if proc.returncode != 0:
        stderr = proc.stderr.decode()
        if "mlir_ktdp" in stderr or "tools_ktdp" in stderr:
            hint = (
                "MLIRFrontendParser (mlir_ktdp) is not installed; install the "
                "bindings from the ktir-mlir-frontend submodule via the "
                "'spyre-test' extra (see setup.py)."
            )
        else:
            hint = "MLIRFrontendParser raised an error (mlir_ktdp is installed)."
        raise RuntimeError(
            f"MLIR parse worker failed. {hint}"
            f"\n--- worker stderr ---\n{stderr}"
        )
    return pickle.loads(proc.stdout)


def _parse_regex(mlir_text: str):
    """Parse via ktir_cpu's pure-Python regex KTIRParser; return an IRModule.

    Backup for ``_parse_mlir_frontend``. Runs in-process (no mlir_ktdp, so no
    dual-MLIR concern), but the regex parser mis-parses function signatures
    when ``loc(...)`` annotations are present, so strip them first. It also has
    known gaps the frontend parser does not (e.g. multi-result ``scf.for``
    group syntax ``%x#0`` / ``%x#1``).

    Currently unused — ``run_cpu`` always uses ``_parse_mlir_frontend``. To
    fall back to this (e.g. when mlir_ktdp is unavailable), swap the call in
    ``run_cpu``, or add a runtime switch (env var / marker) there.
    """
    from ktir_cpu.parser import KTIRParser
    text = re.sub(r"\s*loc\([^)]*(?:\([^)]*\))*[^)]*\)", "", mlir_text)
    text = "\n".join(
        line for line in text.split("\n") if not line.strip().startswith("#loc")
    )
    return KTIRParser().parse_module(text)
# --- END --- added for spyre


class KTIRCpuTester:
    """Mixin that adds numerical CPU execution via ``ktir_cpu``.

    Designed for multiple inheritance with :class:`KTIRStructuralTester`::

        class TestVectorAdd(KTIRCpuTester, KTIRStructuralTester):
            EXAMPLE = "vector_add"

            def test_numerical(self):
                out = self.run_cpu("add_kernel", arg0=x, arg1=y, arg2=output)
                np.testing.assert_allclose(out["arg2"], ref)

    Requires ``self.mod`` (a live ``ir.module``) to be set by
    ``setup_method``. If ``ktir_cpu`` is not installed, :meth:`run_cpu`
    raises ``pytest.skip``.

    Parsing uses ``_parse_mlir_frontend`` (MLIRFrontendParser) by default;
    ``_parse_regex`` is an unwired backup. See those helpers for details.
    """

    def run_cpu(self, func_name: str, *, kernel_fn, **kwargs):
        """Execute ``self.mod`` via the ``ktir_cpu`` interpreter.

        The Spyre pipeline renames ``@triton.jit`` args to ``arg0``,
        ``arg1``, … positionally, so ktir_cpu's declared arg list is
        ``['arg0', 'arg1', …]`` regardless of the original source-level
        names. We do the name-based remap here using ``kernel_fn``'s
        Python signature — that way callers pass ``output_ptr=...``,
        ``input_ptr=...`` etc. in any order, and a typo or missing
        kwarg raises a clear error instead of silently positional-
        matching the wrong buffer to the wrong slot.

        ``kernel_fn`` is keyword-only and required. Caller usually has
        it from the meta.py entry: ``run_cpu(name, kernel_fn=entry["kernel_fn"], ...)``.

        ``kwargs`` keys must be the source-level names from
        ``kernel_fn``'s Python signature, minus any constexpr-baked
        names (those aren't runtime args). Unknown names raise
        ``ValueError``; missing runtime args raise ``ValueError``.

        Returns outputs keyed by the caller's source-level names.
        """
        import pytest
        import inspect
        try:
            from ktir_cpu import KTIRInterpreter
        except ImportError:
            pytest.skip("ktir_cpu not installed — skipping numerical check")

        # --- START --- added for spyre: parse MLIR, then execute in-process.
        # Uses the out-of-process MLIRFrontendParser (see class docstring).
        # _parse_regex is the available backup; not wired up here yet.
        try:
            module = _parse_mlir_frontend(str(self.mod))
        except RuntimeError as e:
            pytest.fail(str(e))
        interp = KTIRInterpreter()
        interp.module = module
        # --- END --- added for spyre

        # Name → argN index, based on @triton.jit's Python arg order.
        raw_fn = getattr(kernel_fn, "fn", kernel_fn)
        source_names = list(inspect.signature(raw_fn).parameters)
        declared = interp.module.get_function(func_name).arg_names

        # Build the source-level-name → argN map for only the runtime
        # args the KTIR function actually declares (constexprs are
        # elided from ktir_cpu's signature).
        runtime_names = source_names[:len(declared)]
        name_to_arg = dict(zip(runtime_names, declared))

        unknown = set(kwargs) - set(runtime_names)
        if unknown:
            raise ValueError(
                f"run_cpu: unknown kwargs {sorted(unknown)} — declared "
                f"runtime args are {runtime_names}"
            )
        missing = set(runtime_names) - set(kwargs)
        if missing:
            raise ValueError(
                f"run_cpu: missing kwargs {sorted(missing)} — declared "
                f"runtime args are {runtime_names}"
            )

        argN_kwargs = {name_to_arg[k]: v for k, v in kwargs.items()}
        raw_outputs = interp.execute_function(func_name, **argN_kwargs)

        # Rename argN back to caller's source-level names.
        arg_to_name = {v: k for k, v in name_to_arg.items()}
        return {arg_to_name[k]: v for k, v in raw_outputs.items() if k in arg_to_name}


# ---------------------------------------------------------------------------
# SinglePassTester — run one pass on inline MLIR text
# ---------------------------------------------------------------------------

class SinglePassTester(StructuralAssertions):
    """Base class for unit-testing individual lowering passes.

    Subclass, set ``PASS`` to a pass-adder function name under
    ``spyre.passes.ttir_to_ktdp``, and call :meth:`run` with inline MLIR.

    Example::

        class TestSplat(SinglePassTester):
            PASS = "add_lower_compute_ops"

            def test_f32(self):
                self.run('''
                module {
                  tt.func @k(%s: f32) {
                    %0 = tt.splat %s : f32 -> tensor<4xf32>
                    tt.return
                  }
                }
                ''')
                self.assert_present("linalg.fill")
                self.assert_absent("tt.splat")
    """

    PASS: str = None

    def _build_passes(self, pm):
        """Install the passes to run on the test module.

        Default behaviour is to add the single pass named by ``self.PASS``.
        Subclasses needing a multi-pass pipeline (e.g. DistributeWork,
        which requires ``add_convert_functions`` first) override this and
        install whatever sequence of passes they need on *pm*.
        """
        from triton._C.libtriton import spyre
        getattr(spyre.passes.ttir_to_ktdp, self.PASS)(pm)

    def _setup_pass(self, mlir_text: str):
        """Parse *mlir_text* and prepare a pass manager. Returns ``(mod, pm)``.

        Subclasses should not need to override this. Override
        :meth:`_build_passes` to customise the pass pipeline.
        """
        from triton._C.libtriton import ir
        from triton.backends.compiler import GPUTarget
        from backend.compiler import SpyreBackend

        target = GPUTarget(backend="spyre", arch=1, warp_size=1)
        backend = SpyreBackend(target)

        ctx = ir.context()
        ir.load_dialects(ctx)
        backend.load_dialects(ctx)

        with tempfile.NamedTemporaryFile(
                mode="w", suffix=".mlir", delete_on_close=False) as f:
            f.write(mlir_text)
            f.flush()
            mod = ir.parse_mlir_module(f.name, ctx)

        mod.context = ctx

        pm = ir.pass_manager(ctx)
        self._build_passes(pm)
        return mod, pm

    def run(self, mlir_text: str):
        """Parse *mlir_text*, run the configured passes, populate ``self.ops``."""
        mod, pm = self._setup_pass(mlir_text)
        pm.run(mod, self.PASS or type(self).__name__)

        self.mod = mod
        self.ops = walk_module(self.mod)
        self._def_map = None
        return self.ops
